/**
 * 数据大小计量单位
 * - Byte
 * - Kb
 * - Mb
 * - Gb
 * - Tb
 */
export const Byte = 1;
export const KB = 1024 * Byte;
export const MB = 1024 * KB;
export const GB = 1024 * MB;
export const TB = 1024 * GB;

